def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Group triples by subject
    subj_groups: dict[str, list[Triple]] = defaultdict(list)
    for t in triples:
        subj_groups[t.subject].append(t)

    # Choose the subject with the most information as the main focus
    main_subject = max(subj_groups.items(), key=lambda kv: len(kv[1]))[0]
    main_triples = subj_groups[main_subject]

    # Helper to join list with commas and "and"
    def join_list(items: list[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Collect information for the main subject
    genre = None
    occupation = None
    origin = None
    birth = None
    death = None
    instruments = []
    associations = []
    other_clauses = []

    for t in main_triples:
        p, o = t.predicate, t.object
        if p == "genre":
            genre = o.lower()
        elif p == "occupation":
            occupation = o.lower()
        elif p == "origin":
            origin = o
        elif p in ("birthDate", "birthYear"):
            birth = o
        elif p in ("deathDate", "deathPlace"):
            death = o
        elif p == "instrument":
            instruments.append(o)
        elif p == "associatedBand/associatedMusicalArtist":
            associations.append(o)
        else:
            # generic fallback clause for less common predicates
            other_clauses.append(f"{main_subject} {p} {o}")

    # Build the main description clause
    description_parts = []

    # Genre + occupation phrasing
    if genre and occupation:
        description_parts.append(f"{main_subject} is a {genre} {occupation}")
    elif genre:
        # assume musician if genre present
        description_parts.append(f"{main_subject} is a {genre} musician")
    elif occupation:
        description_parts.append(f"{main_subject} works as {occupation}")

    # Associations
    if associations:
        assoc_str = join_list(associations)
        description_parts.append(f"associated with {assoc_str}")

    # Instruments
    if instruments:
        instr_str = join_list(instruments)
        description_parts.append(f"plays {instr_str}")

    # Origin
    if origin:
        description_parts.append(f"originates from {origin}")

    # Birth / death
    if birth:
        description_parts.append(f"was born in {birth}")
    if death:
        description_parts.append(f"died in {death}")

    # Combine description parts
    main_clause = ", ".join(description_parts)

    # Process remaining subjects (e.g., bands) into additional clauses
    extra_clauses = []
    for subj, trips in subj_groups.items():
        if subj == main_subject:
            continue
        # Simple aggregation for each secondary subject
        for key, objs in defaultdict(list, {(t.predicate): [] for t in trips}).items():
            pass  # placeholder to keep structure
        # Build simple statements for secondary subject
        for t in trips:
            p, o = t.predicate, t.object
            if p == "bandMember":
                extra_clauses.append(f"{subj} has band member {o}")
            elif p == "genre":
                extra_clauses.append(f"{subj} plays {o.lower()} music")
            else:
                extra_clauses.append(f"{subj} {p} {o}")

    # Assemble final sentence
    all_clauses = [main_clause] + extra_clauses + other_clauses
    sentence = "; ".join(all_clauses).strip()
    if not sentence.endswith("."):
        sentence += "."
    return sentence

